 15→export function EntityDetailPanel({
 16→  entityId,
 17→  workspaceId,
 18→  onClose,
 19→  onEntityClick,
 20→}: {
 21→  entityId: string;
 22→  workspaceId: string;
 23→  onClose: () => void;
 24→  onEntityClick: (entityId: string) => void;
 25→}) {
 26→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 27→  const [loading, setLoading] = useState(true);
 28→  const [error, setError] = useState<string | undefined>();
 29→  const [actionPending, setActionPending] = useState(false);
 30→  const navigateToChat = useViewState((s) => s.navigateToChat);
 31→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
 32→  const navigate = useNavigate();
 33→
 34→  useEffect(() => {
 35→    setLoading(true);
 36→    setError(undefined);
 37→
 38→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 39→      .then(async (response) => {
 40→        if (!response.ok) {
 41→          const body = await response.text();
 42→          throw new Error(body);
 43→        }
 44→        return response.json() as Promise<EntityDetailResponse>;
 45→      })
 46→      .then((data) => {
 47→        setDetail(data);
 48→        setLoading(false);
 49→      })
 50→      .catch((err) => {
 51→        setError(err instanceof Error ? err.message : "Failed to load entity");
 52→        setLoading(false);
 53→      });
 54→  }, [entityId, workspaceId]);
 55→
 56→  function handleJumpToMessage(messageId: string) {
 57→    navigateToChat(messageId);
 58→    void navigate({ to: "/" });
 59→  }
 60→
 61→  async function handleConfirm() {
 62→    if (!detail || actionPending) return;
 63→    setActionPending(true);
 64→    try {
 65→      await confirmDecision(workspaceId, entityId);
 66→      setDetail((prev) =>
 67→        prev
 68→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 69→          : prev,
 70→      );
 71→    } finally {
 72→      setActionPending(false);
 73→    }
 74→  }
 75→
 76→  async function handleOverride() {
 77→    if (!detail || actionPending) return;
 78→    const newSummary = window.prompt("New decision summary:");
 79→    if (!newSummary) return;
 80→    setActionPending(true);
 81→    try {
 82→      await overrideDecision(workspaceId, entityId, newSummary);
 83→      setDetail((prev) =>
 84→        prev
 85→          ? {
 86→              ...prev,
 87→              entity: {
 88→                ...prev.entity,
 89→                name: newSummary,
 90→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
 91→              },
 92→            }
 93→          : prev,
 94→      );
 95→    } finally {
 96→      setActionPending(false);
 97→    }
 98→  }
 99→
100→  async function handleComplete() {
101→    if (!detail || actionPending) return;
102→    setActionPending(true);
103→    try {
104→      await markTaskComplete(workspaceId, entityId);
105→      setDetail((prev) =>
106→        prev
107→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
108→          : prev,
109→      );
110→    } finally {
111→      setActionPending(false);
112→    }
113→  }
114→
115→  if (loading) {
116→    return (
117→      <aside className="entity-detail-panel">
118→        <p className="entity-detail-meta">Loading...</p>
119→      </aside>
120→    );
121→  }
122→
123→  if (error || !detail) {
124→    return (
125→      <aside className="entity-detail-panel">
126→        <div className="entity-detail-header">
127→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
128→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
129→        </div>
130→      </aside>
131→    );
132→  }
133→
134→  const kind = detail.entity.kind as EntityKind;
135→  const status = (detail.entity.data.status as string | undefined) ?? "";
136→  const rationale = detail.entity.data.rationale as string | undefined;
137→
138→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
139→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
140→  const showComplete = kind === "task" && status !== "done";
141→
142→  return (
143→    <aside className="entity-detail-panel">
144→      <div className="entity-detail-header">
145→        <div>
146→          <EntityBadge kind={kind} />
147→          <h3>{detail.entity.name}</h3>
148→        </div>
149→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
150→      </div>

